import { NextResponse } from 'next/server';
import { GoogleGenAI } from '@google/genai';

export async function POST(request: Request) {
  try {
    const { query, products } = await request.json();
    
    if (!process.env.GEMINI_API_KEY) {
      console.log("No GEMINI_API_KEY found, returning mock search result");
      // Mock logic: try to extract a known category from the query
      const categories = Array.from(new Set(products.map((p: any) => p.category)));
      const lowerQuery = query.toLowerCase();
      
      let matchedCategory = "All";
      for (const c of categories) {
        if (lowerQuery.includes((c as string).toLowerCase())) {
          matchedCategory = c as string;
          break;
        }
      }

      // Extract price constraint
      let cleanQuery = lowerQuery;
      const underMatch = lowerQuery.match(/under (\d+)/);
      if (underMatch) {
        cleanQuery = cleanQuery.replace(underMatch[0], "").trim();
      }
      
      // Clean up common fluff words
      cleanQuery = cleanQuery.replace(/healthy|cheap|best|some|any/g, "").trim();

      return NextResponse.json({ category: matchedCategory, cleanQuery: cleanQuery || "under " + (underMatch ? underMatch[1] : "") });
    }

    const ai = new GoogleGenAI({ apiKey: process.env.GEMINI_API_KEY });
    
    const categories = Array.from(new Set(products.map((p: any) => p.category)));

    const prompt = `You are a smart search assistant for a grocery app.
The user searched for: "${query}"

Available categories are: ${categories.join(", ")}

Analyze the search query. Determine if it implies a specific category.
Also, simplify the query to just the core product name or intent (and keep price constraints like "under 50").
Return ONLY a valid JSON object in this format:
{
  "category": "Dairy", // or "All" if no specific category is implied
  "cleanQuery": "milk under 50" // the simplified search string
}`;

    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: prompt,
      config: {
        responseMimeType: "application/json",
      }
    });

    const text = response.text;
    if (text) {
        return NextResponse.json(JSON.parse(text));
    } else {
        throw new Error("Empty response from AI");
    }
  } catch (error) {
    console.error(error);
    return NextResponse.json({ error: 'Failed to process AI request' }, { status: 500 });
  }
}
